import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    def calculate_priority(start_window, end_window, travel, arrival_time):
        if arrival_time < start_window:
            wait_time = start_window - arrival_time
            return wait_time + 0.1 * travel  # prioritize waiting less and shorter travel
        elif arrival_time > end_window:
            return float('inf')  # very high penalty to avoid missing the window
        else:
            return 0.1 * travel  # prioritize shorter travel

    best_node = None
    lowest_priority = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        travel = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel
        start_window, end_window = time_windows[index]

        priority = calculate_priority(start_window, end_window, travel, arrival_time)

        if priority < lowest_priority:
            lowest_priority = priority
            best_node = index

    return best_node
